(function(){function ready(fn){if(document.readyState!=="loading"){fn();return}document.addEventListener("DOMContentLoaded",fn)}ready(function(){var nav=document.getElementById("site-nav");if(nav){var button=nav.querySelector("button");var hidden=nav.querySelector(".hidden-links");if(button&&hidden){button.addEventListener("click",function(){hidden.classList.toggle("hidden");button.classList.toggle("close");nav.classList.toggle("menu-open");button.setAttribute("aria-expanded",nav.classList.contains("menu-open")?"true":"false")})}}var urls=document.querySelector(".author__urls");function syncAuthorUrls(){if(!urls)return;urls.style.display=window.innerWidth>925?"block":"none"}syncAuthorUrls();window.addEventListener("resize",syncAuthorUrls,{passive:true});var reduce=window.matchMedia&&window.matchMedia("(prefers-reduced-motion: reduce)").matches;var reveal=document.querySelectorAll(".reveal,.publication-card,.timeline__entry");if(reduce||!("IntersectionObserver"in window)){reveal.forEach(function(item){item.classList.add("is-visible")})}else{var observer=new IntersectionObserver(function(entries){entries.forEach(function(entry){if(entry.isIntersecting){entry.target.classList.add("is-visible");observer.unobserve(entry.target)}})},{threshold:.08,rootMargin:"0px 0px -28px"});reveal.forEach(function(item){observer.observe(item)})}var links=document.querySelectorAll('.greedy-nav a[href*="#"]');var sections=[];links.forEach(function(link){var hash=link.getAttribute("href").split("#")[1];var section=hash&&document.getElementById(hash);if(section){sections.push({link:link,section:section})}});function activeLink(){var current=null;sections.forEach(function(item){if(item.section.getBoundingClientRect().top<=150){current=item}});links.forEach(function(link){link.removeAttribute("aria-current")});if(current){current.link.setAttribute("aria-current","true")}}if(sections.length){activeLink();window.addEventListener("scroll",activeLink,{passive:true});window.addEventListener("hashchange",function(){requestAnimationFrame(activeLink)})}})})();
